def _find_option_value(ctx: Context, opt: str) -> t.Any | None:
    """Look up the current value of another option on the same command
    by one of its declared option strings (e.g. ``"--protocol"``).
    """
    for param in ctx.command.get_params(ctx):
        if opt in param.opts or opt in param.secondary_opts:
            return ctx.params.get(param.name)  # type: ignore[arg-type]

    return None


def _resolve_dynamic_defaults(ctx: Context) -> None:
    """Second-pass resolution of dynamic (dict-based) option defaults.

    Runs after all command-line arguments, environment variables, and
    default maps have been processed, so that dynamic defaults can react
    to the fully resolved values of the options they depend on.
    """
    for param in ctx.command.get_params(ctx):
        if not isinstance(param, Option) or not param._dynamic_default:
            continue

        if ctx.get_parameter_source(param.name) != ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved = None

        for opt, mapping in param._dynamic_default.items():
            source_value = _find_option_value(ctx, opt)

            if source_value is None:
                continue

            key = str(source_value)

            if key in mapping:
                resolved = mapping[key]

        if resolved is None:
            continue

        with augment_usage_errors(ctx, param=param):
            value = param.type_cast_value(ctx, resolved)

            if param.callback is not None:
                value = param.callback(ctx, param, value)

        if param.expose_value:
            ctx.params[param.name] = value  # type: ignore[index]"}

